import React, { useMemo } from 'react';
import { Tabs, type Tab } from '@linm-soft-org/linm-web-common-components';
import { useWorkspaceTabsOptional } from './WorkspaceTabProvider';
import styles from './WorkspaceTabBar.module.css';

export const WorkspaceTabBar: React.FC = () => {
  const workspace = useWorkspaceTabsOptional();
  const tabs = workspace?.tabs ?? [];
  const activeTabId = workspace?.activeTabId;
  const activateTab = workspace?.activateTab;
  const closeTab = workspace?.closeTab;

  const tabItems: Tab[] = useMemo(
    () =>
      tabs.map(t => ({
        id: t.id,
        label: t.title,
        closable: true,
      })),
    [tabs],
  );

  if (!workspace || tabs.length === 0 || !activeTabId || !activateTab) return null;

  return (
    <div className={styles.bar} data-testid="erp-workspace-tab-bar">
      <Tabs
        tabs={tabItems}
        activeTab={activeTabId}
        onTabChange={activateTab}
        onTabClose={closeTab ?? undefined}
        variant="underline"
        sticky
      />
    </div>
  );
};
