/** Webpack standalone build (`yarn start:std`). DefinePlugin injects `'true'` | `'false'`. */
export const isStandalone = import.meta.env.VITE_STANDALONE === 'true';

/** Standalone dev uses `StandaloneMockTopbar` + `mainEmbedded` — parity @linm/nav shell. */
export const standaloneEmbeddedShell = isStandalone;

/** Hiện route `/dev` khi dev server hoặc standalone. */
export const showDevNav = import.meta.env.DEV || isStandalone;
